const cellKey = (x: number, y: number): string => `${x},${y}`;

const parseCellKey = (key: string): Cell => {
  const [xStr, yStr] = key.split(",");
  return [Number(xStr), Number(yStr)];
};

export function nextGeneration(cells: Cell[]): Cell[] {
  const liveSet = new Set<string>(cells.map(([x, y]) => cellKey(x, y)));

  const neighborCounts = new Map<string, number>();
  for (const [x, y] of cells) {
    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
      const key = cellKey(x + dx, y + dy);
      neighborCounts.set(key, (neighborCounts.get(key) ?? 0) + 1);
    }
  }

  const result: Cell[] = [];
  for (const [key, neighborCount] of neighborCounts) {
    const isAlive = liveSet.has(key);
    const survives = isAlive && neighborCount === 2;
    const isBorn = neighborCount === 3;
    if (survives || isBorn) {
      result.push(parseCellKey(key));
    }
  }

  return result;
}

