const cellKey = (x: number, y: number): string => `${x},${y}`;

export function nextGeneration(cells: Cell[]): Cell[] {
  const liveSet = new Set<string>(cells.map(([x, y]) => cellKey(x, y)));

  const neighborCounts = new Map<string, { cell: Cell; count: number }>();
  for (const [x, y] of cells) {
    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
      const nx = x + dx;
      const ny = y + dy;
      const key = cellKey(nx, ny);
      const existing = neighborCounts.get(key);
      if (existing) {
        existing.count += 1;
      } else {
        neighborCounts.set(key, { cell: [nx, ny], count: 1 });
      }
    }
  }

  const result: Cell[] = [];
  for (const [key, { cell, count }] of neighborCounts) {
    const isAlive = liveSet.has(key);
    const survives = isAlive && count === 2;
    const isBorn = count === 3;
    if (survives || isBorn) {
      result.push(cell);
    }
  }

  return result;
}

